const payload = $json.body || $json;

let interaction = payload.interaction || {};

if (typeof interaction === 'string') {
  try {
    interaction = JSON.parse(interaction);
  } catch (error) {
    interaction = {};
  }
}

const options = interaction.data?.options || [];
const resolved = interaction.data?.resolved || {};

function getOption(name) {
  return options.find((option) => option.name === name)?.value || null;
}

const acao = getOption('acao');
const instrucoes = getOption('instrucoes') || '';
const arquivoId = getOption('arquivo');
const arquivo = resolved.attachments?.[arquivoId];

const applicationId = payload.applicationId || payload.application_id || interaction.application_id;
const token = payload.token || interaction.token;

if (!applicationId || !token) {
  return [{
    json: {
      erro: true,
      applicationId,
      token,
      mensagem: '❌ Não foi possível localizar applicationId ou token da interação.'
    }
  }];
}

if (!arquivo) {
  return [{
    json: {
      erro: true,
      applicationId,
      token,
      mensagem: '❌ Nenhum arquivo foi encontrado no comando /ndoc.'
    }
  }];
}

const nome = arquivo.filename || '';
const extensao = nome.toLowerCase().slice(nome.lastIndexOf('.'));

if (!['.pdf', '.docx', '.txt'].includes(extensao)) {
  return [{
    json: {
      erro: true,
      applicationId,
      token,
      mensagem: '❌ Formato inválido. Envie apenas arquivos PDF, DOCX ou TXT.'
    }
  }];
}

return [{
  json: {
    erro: false,
    applicationId,
    token,
    acao,
    instrucoes,
    arquivoNome: nome,
    arquivoUrl: arquivo.url,
    arquivoTamanho: arquivo.size,
    extensao,
    contentType: arquivo.content_type || ''
  }
}];

const texto = $json.text || $json.data || $json.content || '';
const acao = $('Extrair Dados').item.json.acao;
const instrucoes = $('Extrair Dados').item.json.instrucoes;
const arquivoNome = $('Extrair Dados').item.json.arquivoNome;
const applicationId = $('Extrair Dados').item.json.applicationId;
const token = $('Extrair Dados').item.json.token;

let tarefa = 'Analise este documento.';

if (acao === 'resumo') tarefa = 'Gere um resumo objetivo deste documento.';
if (acao === 'requisitos') tarefa = 'Extraia requisitos funcionais e não funcionais deste documento.';
if (acao === 'negocio') tarefa = 'Extraia regras de negócio deste documento.';
if (acao === 'pendencias') tarefa = 'Identifique pendências, riscos e pontos em aberto deste documento.';
if (acao === 'tarefas') tarefa = 'Transforme este documento em uma lista de tarefas práticas.';

return [{
  json: {
    applicationId,
    token,
    prompt: `Você é o NIC Doc AI, um assistente especializado em análise de documentos.\n\nArquivo: ${arquivoNome}\nTipo de análise: ${acao}\nInstruções adicionais: ${instrucoes || 'Nenhuma'}\n\nTarefa: ${tarefa}\n\nResponda em português do Brasil, de forma organizada e profissional.\n\nConteúdo do documento:\n${String(texto).slice(0, 80000)}`
  }
}];

