const resposta = $json.choices?.[0]?.message?.content || 'Não foi possível gerar a análise.';
const applicationId = $('Montar Prompt').item.json.applicationId;
const token = $('Montar Prompt').item.json.token;

const content = resposta.length > 1900
  ? resposta.slice(0, 1900) + '\n\n⚠️ Resposta cortada por limite do Discord.'
  : resposta;

return [{
  json: {
    applicationId,
    token,
    content
  }
}];

const secretRecebido = String($json.headers["x-nic-automation-secret"] || "").trim();
const secretEsperado = "Nic_labsautomationsecret145885454548547";

if (secretRecebido !== secretEsperado) {
  throw new Error("Acesso negado: secret inválido");
}

return [
  {
    json: $json
  }
];
